#include <iostream>
using namespace std;
bool isPalindrome(int arr[], int n) {
    for(int i=0; i<n/2; i++) {
        if(arr[i] != arr[n-i-1]) return false;
    }
    return true;
}
int main() {
    int arr[] = {1, 2, 3, 2, 1};
    if(isPalindrome(arr, 5)) cout << "Palindrome";
    else cout << "Not Palindrome";
    return 0;
}
